def should_write_memory(query: str, answer: str, decision: RouteDecision) -> bool:
    if contains_explicit_save_intent(query):
        return True

    if decision.route in {"context_memory_glm", "report_skill_glm"}:
        if contains_project_decision(query, answer):
            return True
        if contains_experiment_result(answer):
            return True
        if contains_design_summary(answer):
            return True
        if contains_open_task(answer):
            return True

    return False
